import{c as a,Q as i,j as t,m as l}from"./chunks/framework.GMXXjwDt.js";const c=JSON.parse('{"title":"安装部署指南","description":"","frontmatter":{},"headers":[],"relativePath":"install.md","filePath":"install.md"}'),e={name:"install.md"};function n(h,s,p,d,r,o){return i(),t("div",null,[...s[0]||(s[0]=[l(`<h1 id="安装部署指南" tabindex="-1">安装部署指南 <a class="header-anchor" href="#安装部署指南" aria-label="Permalink to &quot;安装部署指南&quot;">​</a></h1><p>本文档介绍如何部署 FLVX 面板端及节点端。</p><h2 id="一、面板端部署" tabindex="-1">一、面板端部署 <a class="header-anchor" href="#一、面板端部署" aria-label="Permalink to &quot;一、面板端部署&quot;">​</a></h2><p>面板端负责管理用户、节点和转发规则。</p><h3 id="_1-环境要求" tabindex="-1">1. 环境要求 <a class="header-anchor" href="#_1-环境要求" aria-label="Permalink to &quot;1. 环境要求&quot;">​</a></h3><ul><li>操作系统：Linux (推荐 Debian 10+ / Ubuntu 20.04+)</li><li>必须安装 Docker 和 Docker Compose</li></ul><h3 id="_2-一键安装脚本" tabindex="-1">2. 一键安装脚本 <a class="header-anchor" href="#_2-一键安装脚本" aria-label="Permalink to &quot;2. 一键安装脚本&quot;">​</a></h3><p>使用以下命令即可快速安装面板：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/iKeilo/flvxt2/main/panel_install.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> panel_install.sh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +x</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> panel_install.sh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./panel_install.sh</span></span></code></pre></div><p><strong>安装过程中会提示输入以下信息：</strong></p><ul><li><strong>前端端口</strong>: 默认为 <code>6366</code></li><li><strong>后端端口</strong>: 默认为 <code>6365</code></li></ul><p>脚本会自动检测系统是否支持 IPv6，并自动配置 Docker 的 IPv6 支持。</p><h3 id="_3-访问面板" tabindex="-1">3. 访问面板 <a class="header-anchor" href="#_3-访问面板" aria-label="Permalink to &quot;3. 访问面板&quot;">​</a></h3><p>安装完成后，访问： <code>http://&lt;服务器IP&gt;:&lt;前端端口&gt;</code> (默认: <code>http://&lt;服务器IP&gt;:6366</code>)</p><p><strong>默认管理员账号：</strong></p><ul><li>用户名: <code>admin_user</code></li><li>密码: <code>admin_user</code></li></ul><blockquote><p>⚠️ <strong>注意</strong>: 首次登录后，请务必在“个人中心”或“设置”中修改默认密码！</p></blockquote><h3 id="_4-维护命令" tabindex="-1">4. 维护命令 <a class="header-anchor" href="#_4-维护命令" aria-label="Permalink to &quot;4. 维护命令&quot;">​</a></h3><p>再次运行 <code>./panel_install.sh</code> 脚本可以看到管理菜单：</p><ol><li>安装面板</li><li>更新面板</li><li>卸载面板</li><li>迁移到 PostgreSQL</li><li>退出</li></ol><hr><h2 id="二、节点端部署" tabindex="-1">二、节点端部署 <a class="header-anchor" href="#二、节点端部署" aria-label="Permalink to &quot;二、节点端部署&quot;">​</a></h2><p>节点端运行在实际进行流量转发的服务器上，需要连接到面板端进行管理。</p><h3 id="_1-获取接入密钥" tabindex="-1">1. 获取接入密钥 <a class="header-anchor" href="#_1-获取接入密钥" aria-label="Permalink to &quot;1. 获取接入密钥&quot;">​</a></h3><ol><li>登录面板端。</li><li>进入 <strong>节点管理 (Node)</strong> 页面。</li><li>点击 <strong>添加节点</strong>。</li><li>获取该节点的 <strong>接入密钥 (Secret)</strong>。</li></ol><h3 id="_2-一键安装脚本-1" tabindex="-1">2. 一键安装脚本 <a class="header-anchor" href="#_2-一键安装脚本-1" aria-label="Permalink to &quot;2. 一键安装脚本&quot;">​</a></h3><p>在节点服务器上运行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/iKeilo/flvxt2/main/install.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install.sh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +x</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install.sh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./install.sh</span></span></code></pre></div><p><strong>安装过程中会提示输入：</strong></p><ul><li><strong>服务器地址</strong>: 面板端的通信地址（通常是 <code>http://&lt;面板IP&gt;:&lt;后端端口&gt;</code>，例如 <code>http://1.2.3.4:6365</code>）。</li><li><strong>密钥</strong>: 刚才在面板中获取的节点密钥。</li></ul><p>或者直接使用带参数的命令（适用于自动化部署）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 替换 &lt;面板地址&gt; 和 &lt;密钥&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./install.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;http://1.2.3.4:6365&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;your_node_secret&quot;</span></span></code></pre></div><h3 id="_3-验证安装" tabindex="-1">3. 验证安装 <a class="header-anchor" href="#_3-验证安装" aria-label="Permalink to &quot;3. 验证安装&quot;">​</a></h3><p>安装完成后，服务会自动启动。</p><ul><li>查看状态: <code>systemctl status flvx_agent</code>（旧版为 <code>flux_agent</code>）</li><li>回到面板 <strong>节点管理</strong> 页面，该节点状态应显示为 <strong>在线</strong>。</li></ul><hr><h2 id="三、caddy-反向代理-可选" tabindex="-1">三、Caddy 反向代理（可选） <a class="header-anchor" href="#三、caddy-反向代理-可选" aria-label="Permalink to &quot;三、Caddy 反向代理（可选）&quot;">​</a></h2><p>如果需要通过域名访问面板并自动获取 HTTPS 证书，可以使用 Caddy 作为反向代理。</p><h3 id="_1-安装-caddy" tabindex="-1">1. 安装 Caddy <a class="header-anchor" href="#_1-安装-caddy" aria-label="Permalink to &quot;1. 安装 Caddy&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Debian / Ubuntu</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> debian-keyring</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> debian-archive-keyring</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt-transport-https</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> curl</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -1sLf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;https://dl.cloudflare.com/content/v1/e2qwFJ2fRP2b2q/stable/gpg.key&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gpg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dearmor</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/share/keyrings/caddy-stable-archive-keyring.gpg</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -1sLf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;https://dl.cloudflare.com/content/v1/e2qwFJ2fRP2b2q/stable/debian.deb.txt&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tee</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/apt/sources.list.d/caddy-stable.list</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> caddy</span></span></code></pre></div><p>其他系统请参考 <a href="https://caddyserver.com/docs/install" target="_blank" rel="noreferrer">Caddy 官方安装文档</a>。</p><h3 id="_2-配置-caddyfile" tabindex="-1">2. 配置 Caddyfile <a class="header-anchor" href="#_2-配置-caddyfile" aria-label="Permalink to &quot;2. 配置 Caddyfile&quot;">​</a></h3><p>编辑 Caddy 配置文件：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nano</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/caddy/Caddyfile</span></span></code></pre></div><h4 id="面板域名配置" tabindex="-1">面板域名配置 <a class="header-anchor" href="#面板域名配置" aria-label="Permalink to &quot;面板域名配置&quot;">​</a></h4><p>将 <code>panel.example.com</code> 替换为你自己的域名：</p><div class="language-caddyfile vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">caddyfile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>panel.example.com {</span></span>
<span class="line"><span>    reverse_proxy localhost:6366</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Caddy 会自动为域名申请和续期 HTTPS 证书，无需额外配置。</p><h3 id="_3-重启-caddy" tabindex="-1">3. 重启 Caddy <a class="header-anchor" href="#_3-重启-caddy" aria-label="Permalink to &quot;3. 重启 Caddy&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> caddy</span></span></code></pre></div><h3 id="_4-注意事项" tabindex="-1">4. 注意事项 <a class="header-anchor" href="#_4-注意事项" aria-label="Permalink to &quot;4. 注意事项&quot;">​</a></h3><ul><li>确保域名已正确解析到服务器 IP。</li><li>确保服务器防火墙放行了 <strong>80</strong> 和 <strong>443</strong> 端口（Caddy 自动申请证书需要）。</li><li>使用 Caddy 反向代理后，可以在 <code>.env</code> 中将前端端口改为仅监听本地，避免直接暴露：<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>FRONTEND_PORT=127.0.0.1:6366</span></span></code></pre></div></li></ul>`,52)])])}const g=a(e,[["render",n]]);export{c as __pageData,g as default};
